# Check unsigned greater-than pattern
def check_ugt(bits=8):
    max_val = (1 << bits) - 1
    for x in range(1 << bits):
        for y in range(1 << bits):
            s = (x + y) % (1 << bits)

            cond_x = s > x
            cond_y = s > y

            if cond_x != cond_y:
                print(f"Mismatch UGT: x={x}, y={y}, s={s}, cond_x={cond_x}, cond_y={cond_y}")
                return False
    return True

print("UGT equivalence:", check_ugt())

# Also check ULE and UGE
def check_ule(bits=8):
    for x in range(1 << bits):
        for y in range(1 << bits):
            s = (x + y) % (1 << bits)
            cond_x = s <= x
            cond_y = s <= y
            if cond_x != cond_y:
                return False
    return True

def check_uge(bits=8):
    for x in range(1 << bits):
        for y in range(1 << bits):
            s = (x + y) % (1 << bits)
            cond_x = s >= x
            cond_y = s >= y
            if cond_x != cond_y:
                return False
    return True

print("ULE equivalence:", check_ule())
print("UGE equivalence:", check_uge())
EOF
